ALGORITHM EvaluateQuantified(predicate, domain, quantifier)
BEGIN
  IF quantifier = "FORALL" THEN
    // Universal: must be true for ALL elements
    FOR EACH element IN domain DO
      IF NOT predicate(element) THEN
        RETURN FALSE
      END IF
    END FOR
    RETURN TRUE

  ELSE IF quantifier = "EXISTS" THEN
    // Existential: must be true for AT LEAST ONE element
    FOR EACH element IN domain DO
      IF predicate(element) THEN
        RETURN TRUE
      END IF
    END FOR
    RETURN FALSE
  END IF
END

