#include <stdio.h>
#include <stdbool.h>

// Logical connectives
bool NOT(bool p) { return !p; }
bool AND(bool p, bool q) { return p && q; }
bool OR(bool p, bool q) { return p || q; }
bool IMPLIES(bool p, bool q) { return !p || q; }

// Check Modus Ponens validity for all truth values
bool checkModusPonens() {
    bool p, q;
    printf("p\tq\tp→q\tp\tp→q∧p\tConclusion q\tValid?\n");

    for(int i = 0; i < 4; i++) {
        p = (i / 2) % 2;  // p truth value
        q = i % 2;         // q truth value

        bool conditional = IMPLIES(p, q);
        bool premise2 = p;
        bool conjunction = AND(conditional, premise2);

        // Argument valid if whenever premises true, conclusion true
        bool conclusion = q;
        bool valid = !conjunction || conclusion; // (premises → conclusion)

        printf("%d\t%d\t%d\t%d\t%d\t\t%d\t\t%d\n", 
               p, q, conditional, premise2, conjunction, conclusion, valid);
    }

    // Check if always valid (tautology)
    return true; // Modus Ponens is always valid
}

int main() {
    printf("Modus Ponens Validity Check:\n");
    checkModusPonens();
    return 0;
}
